-- ----------------------------------------------------------------------------
-- vw_dependencies: External tools and their roles
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_dependencies WITH (security_invoker = ON) AS
